args.sparql:
SELECT ?stateLabel WHERE {
  ?lake wdt:P31 wd:Q7129;
          wdt:P17 wd:Q30;
          wdt:P2043 ?depth;
          wdt:P131 ?state.
  ?state rdfs:label ?stateLabel.
  FILTER (LANG(?stateLabel) = 'en')
} ORDER BY DESC(?depth) LIMIT 1

